import React, { useState, useEffect } from 'react';
import Card from '../components/Card';
import Button from '../components/Button';
import { serviceAPI, apiUtils } from '../services/api';

const ServiceHistory = () => {
  const [filter, setFilter] = useState('all');
  const [serviceHistory, setServiceHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  // Fetch service history from backend
  useEffect(() => {
    fetchServiceHistory();
  }, []);

  // Add a refresh function that can be called externally
  useEffect(() => {
    const handleFocus = () => {
      fetchServiceHistory(); // Refresh when user comes back to the page
    };

    window.addEventListener('focus', handleFocus);
    return () => window.removeEventListener('focus', handleFocus);
  }, []);

  const fetchServiceHistory = async () => {
    try {
      setLoading(true);
      const response = await serviceAPI.getServiceHistory();

      if (response.data && response.data.services) {
        setServiceHistory(response.data.services);
      }
    } catch (error) {
      setError(apiUtils.formatErrorMessage(error));
    } finally {
      setLoading(false);
    }
  };

  // Dummy service history data (fallback for demo)
  const dummyServiceHistory = [
    {
      id: 'SRV001',
      date: '2024-01-15',
      bikeModel: 'Honda CB Shine',
      serviceType: 'Premium Service',
      amount: 1200,
      status: 'Completed',
      technician: 'John Smith',
      location: 'Doorstep Service',
      description: 'Complete bike service including oil change, brake adjustment, and chain cleaning',
      nextServiceDue: '2024-04-15'
    },
    {
      id: 'SRV002',
      date: '2024-01-08',
      bikeModel: 'Honda CB Shine',
      serviceType: 'Oil Change',
      amount: 400,
      status: 'Completed',
      technician: 'Mike Johnson',
      location: 'Service Center',
      description: 'Engine oil change with filter replacement',
      nextServiceDue: '2024-03-08'
    },
    {
      id: 'SRV003',
      date: '2024-01-20',
      bikeModel: 'Honda CB Shine',
      serviceType: 'Brake Service',
      amount: 600,
      status: 'Pending',
      technician: 'Sarah Wilson',
      location: 'Doorstep Service',
      description: 'Brake pad replacement and brake fluid change',
      nextServiceDue: null
    },
    {
      id: 'SRV004',
      date: '2023-12-10',
      bikeModel: 'Honda CB Shine',
      serviceType: 'Basic Service',
      amount: 500,
      status: 'Completed',
      technician: 'David Brown',
      location: 'Service Center',
      description: 'Basic maintenance and inspection',
      nextServiceDue: '2024-02-10'
    },
    {
      id: 'SRV005',
      date: '2024-01-22',
      bikeModel: 'Honda CB Shine',
      serviceType: 'Emergency Repair',
      amount: 800,
      status: 'Cancelled',
      technician: null,
      location: 'Doorstep Service',
      description: 'Emergency breakdown service - cancelled by customer',
      nextServiceDue: null
    }
  ];

  const getStatusColor = (status) => {
    switch (status.toLowerCase()) {
      case 'completed':
        return 'status-completed';
      case 'pending':
        return 'status-pending';
      case 'cancelled':
        return 'status-cancelled';
      default:
        return 'status-default';
    }
  };

  // Use real data if available, otherwise use dummy data for demo
  const displayHistory = serviceHistory.length > 0 ? serviceHistory : dummyServiceHistory;

  const filteredHistory = displayHistory.filter(service => {
    if (filter === 'all') return true;
    return service.status.toLowerCase() === filter;
  });

  // Calculate totals (using dummy amounts for now since backend doesn't return amounts)
  const totalSpent = filteredHistory
    .filter(service => service.status.toLowerCase() === 'completed')
    .reduce((total, service) => total + (service.amount || 800), 0); // Default amount

  const totalServices = filteredHistory.filter(service => service.status.toLowerCase() === 'completed').length;

  return (
    <div className="service-history">
      <div className="container">
        <div className="page-header">
          <h1>Service History</h1>
          <p>Track all your bike services and maintenance records</p>
        </div>

        {/* Loading State */}
        {loading && (
          <div className="text-center" style={{ padding: '2rem' }}>
            <p>Loading service history...</p>
          </div>
        )}

        {/* Error State */}
        {error && (
          <div className="error-message" style={{ marginBottom: '2rem' }}>
            {error}
          </div>
        )}

        {/* Summary Cards */}
        <div className="summary-cards">
          <Card className="summary-card">
            <div className="summary-icon">📊</div>
            <div className="summary-content">
              <h3>{totalServices}</h3>
              <p>Total Services</p>
            </div>
          </Card>
          <Card className="summary-card">
            <div className="summary-icon">💰</div>
            <div className="summary-content">
              <h3>₹{totalSpent}</h3>
              <p>Total Spent</p>
            </div>
          </Card>
          <Card className="summary-card">
            <div className="summary-icon">🔧</div>
            <div className="summary-content">
              <h3>Honda CB Shine</h3>
              <p>Primary Bike</p>
            </div>
          </Card>
          <Card className="summary-card">
            <div className="summary-icon">📅</div>
            <div className="summary-content">
              <h3>Jan 15, 2024</h3>
              <p>Last Service</p>
            </div>
          </Card>
        </div>

        {/* Filter Buttons */}
        <div className="filter-section">
          <h3>Filter Services</h3>
          <div className="filter-buttons">
            <Button
              variant={filter === 'all' ? 'primary' : 'secondary'}
              onClick={() => setFilter('all')}
            >
              All Services
            </Button>
            <Button
              variant={filter === 'completed' ? 'primary' : 'secondary'}
              onClick={() => setFilter('completed')}
            >
              Completed
            </Button>
            <Button
              variant={filter === 'pending' ? 'primary' : 'secondary'}
              onClick={() => setFilter('pending')}
            >
              Pending
            </Button>
            <Button
              variant={filter === 'cancelled' ? 'primary' : 'secondary'}
              onClick={() => setFilter('cancelled')}
            >
              Cancelled
            </Button>
          </div>
        </div>

        {/* Service History List */}
        <div className="history-section">
          <h3>Service Records</h3>
          {filteredHistory.length === 0 ? (
            <Card className="no-services">
              <div className="no-services-content">
                <div className="no-services-icon">📋</div>
                <h3>No services found</h3>
                <p>No services match the selected filter.</p>
              </div>
            </Card>
          ) : (
            <div className="history-list">
              {filteredHistory.map((service) => (
                <Card key={service.id} className="history-card">
                  <div className="history-header">
                    <div className="history-id">
                      <strong>#{service.id}</strong>
                      <span className={`status-badge ${getStatusColor(service.status)}`}>
                        {service.status_display || service.status}
                      </span>
                    </div>
                    <div className="history-date">
                      {new Date(service.date).toLocaleDateString()}
                    </div>
                  </div>

                  <div className="history-content">
                    <div className="history-main">
                      <h4>{service.service_type_display || service.serviceType}</h4>
                      <p className="history-description">
                        {service.description || `${service.service_type_display || service.serviceType} - ${service.service_category === 'doorstep_service' ? 'Doorstep Service' : 'Regular Service'}`}
                      </p>
                      <div className="history-details">
                        {service.bike_model_display && (
                          <span className="detail-item">
                            <strong>Bike:</strong> {service.bike_model_display}
                          </span>
                        )}
                        <span className="detail-item">
                          <strong>Location:</strong> {service.address}
                        </span>
                        {service.technician && (
                          <span className="detail-item">
                            <strong>Technician:</strong> {service.technician}
                          </span>
                        )}
                      </div>
                    </div>

                    <div className="history-sidebar">
                      <div className="history-amount">₹{service.amount}</div>
                      {service.nextServiceDue && (
                        <div className="next-service">
                          <small>Next service due:</small>
                          <div>{service.nextServiceDue}</div>
                        </div>
                      )}
                    </div>
                  </div>
                </Card>
              ))}
            </div>
          )}
        </div>

        {/* Upcoming Services */}
        <div className="upcoming-section">
          <Card className="upcoming-card">
            <h3>Upcoming Service Reminder</h3>
            <div className="upcoming-content">
              <div className="upcoming-icon">🔔</div>
              <div className="upcoming-info">
                <h4>Next Service Due: April 15, 2024</h4>
                <p>Your Honda CB Shine is due for its next premium service. Book now to maintain optimal performance.</p>
                <Button variant="primary" className="book-service-btn">
                  Book Next Service
                </Button>
              </div>
            </div>
          </Card>
        </div>
      </div>
    </div>
  );
};

export default ServiceHistory;
